from string import Template
from pathlib import Path
from typing import Any
import yaml

class PromptTemplate:
    def __init__(self, template_id: str, version: str) -> None:
        path = Path(f"src/prompts/{template_id}/v{version}.yaml")
        if not path.exists():
            raise FileNotFoundError(f"Prompt template not found: {path}")
        raw = yaml.safe_load(path.read_text())
        self._meta = raw
        self._system_tmpl = Template(raw["system"])
        self._user_tmpl   = Template(raw["user_template"])
        self._variables   = raw.get("variables", {})

    def render(self, **kwargs: Any) -> dict[str, str]:
        # Validate required variables
        for var_name, var_def in self._variables.items():
            if var_def.get("required") and var_name not in kwargs:
                raise ValueError(f"Required variable '{var_name}' not provided")
            if var_name not in kwargs and "default" in var_def:
                kwargs[var_name] = var_def["default"]

        # Validate max_length constraints
        for var_name, value in kwargs.items():
            var_def = self._variables.get(var_name, {})
            if "max_length" in var_def and isinstance(value, str):
                if len(value) > var_def["max_length"]:
                    raise ValueError(
                        f"Variable '{var_name}' exceeds max_length={var_def['max_length']}"
                    )

        # Template.substitute raises KeyError on any undefined $placeholder
        return {
            "system": self._system_tmpl.substitute(kwargs),
            "user":   self._user_tmpl.substitute(kwargs),
        }

    @property
    def contains_user_content(self) -> bool:
        return self._meta.get("contains_user_content", False)

    @property
    def injection_surface(self) -> str:
        return self._meta.get("injection_surface", "low")


# Registry — single source of truth for version pinning
from src.config.prompt_versions import PROMPT_VERSIONS

def get_template(template_id: str) -> PromptTemplate:
    version = PROMPT_VERSIONS[template_id]
    return PromptTemplate(template_id, version)

